<template>
  <div class="publish-page container">
    <UserSidebar active="publish-found" />
    <div class="form-section">
      <el-form :model="form" label-width="100px">
        <el-form-item label="物品名称">
          <el-input v-model="form.title" />
        </el-form-item>
        <el-form-item label="类别">
          <el-select v-model="form.category" placeholder="请选择类别" style="width: 100%">
            <el-option label="证件 (学生证/身份证等)" value="card" />
            <el-option label="电子设备 (手机/电脑等)" value="electronic" />
            <el-option label="书籍 (教材/小说等)" value="book" />
            <el-option label="生活用品 (水杯/雨伞等)" value="daily" />
            <el-option label="其他" value="other" />
          </el-select>
        </el-form-item>
        <el-form-item label="时间">
          <el-date-picker v-model="form.time" type="datetime" />
        </el-form-item>
        <el-form-item label="地点">
          <MapSelector :key="resetKey" :mapSrc="mapImageSrc" @select="p=>point=p" />
        </el-form-item>
        <el-form-item label="描述">
          <el-input type="textarea" v-model="form.description" />
        </el-form-item>
        <el-form-item label="联系方式">
          <el-input v-model="form.contact" placeholder="手机号/微信号/QQ" />
        </el-form-item>
        <el-form-item label="图片">
          <UploadImage :key="resetKey" action="/api/file/upload" @change="imgs=$event" />
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="submit">发布拾物</el-button>
        </el-form-item>
      </el-form>
    </div>
  </div>
</template>
<script setup lang="ts">
import { reactive, ref } from 'vue'
import { ElMessage } from 'element-plus'
import UploadImage from '../components/UploadImage.vue'
import MapSelector from '../components/MapSelector.vue'
import UserSidebar from '../components/UserSidebar.vue'
import http from '../api/http'
let point: any = null
let imgs: string[] = []
const resetKey = ref(0)
const form = reactive({ title:'', category:'', time:'', description:'', contact:'' })
const mapImageSrc = 'data:image/svg+xml;utf8,' + encodeURIComponent(`
  <svg xmlns="http://www.w3.org/2000/svg" width="800" height="500">
    <defs>
      <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
        <path d="M 40 0 L 0 0 0 40" fill="none" stroke="#eee" stroke-width="1"/>
      </pattern>
    </defs>
    <rect width="100%" height="100%" fill="#fafafa"/>
    <rect width="100%" height="100%" fill="url(#grid)"/>
    <text x="50%" y="50%" dominant-baseline="middle" text-anchor="middle" fill="#999" font-size="20">
      校园地图占位图（未提供图片）
    </text>
  </svg>
`)

function formatTime(d: any) {
  if (!d) return ''
  const date = new Date(d)
  const pad = (n: number) => n < 10 ? '0'+n : n
  return `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}`
}

async function submit() {
  const payload = {
    title: form.title, category: form.category, description: form.description,
    latitude: point ? point.y : null, longitude: point ? point.x : null,
    imageUrl: imgs[0] || '', thumbnailUrl: imgs[0] || '',
    foundTime: formatTime(form.time),
    contact: form.contact,
    images: JSON.stringify(imgs),
    pointId: point ? point.id : null
  }
  await http.post('/found/add', payload)
  ElMessage.success('已提交待审核，请继续填写')
  // Reset
  form.title = ''
  form.category = ''
  form.time = ''
  form.description = ''
  form.contact = ''
  point = null
  imgs = []
  resetKey.value++
}
</script>

<style scoped>
.publish-page {
  display: flex;
  gap: 20px;
  margin-top: 24px;
}
.form-section {
  flex: 1;
  background: #fff;
  padding: 30px;
  border-radius: 8px;
}
</style>
